sql:
SELECT COUNT(*) 
FROM ipo_listings 
WHERE issue_type = 'Mainline' AND subscribed > '200x';

SELECT issuer_company, COUNT(*) AS frequency
FROM ipo_listings
GROUP BY issuer_company;

SELECT issuer_company, listing_date
FROM ipo_listings
WHERE issue_type = 'Mainline' AND listing_status = 'Active';

SELECT ipo_id, issuer_company
FROM ipo_listings
WHERE listing_date = (
    SELECT MAX(listing_date) FROM ipo_listings
);

external_knowledge:
- 'Keen interest' is indicated by the user viewing the IPO details multiple times; 
- 'Going public' refers to companies that are listed in the 'ipo_listings' table;
- The number of views captures the level of interest a user has in a specific IPO.

sql:
SELECT il.issuer_company, il.issue_price, sp.current_price
FROM ipo_listings AS il
JOIN stock_prices AS sp ON il.ipo_id = sp.ipo_id;

SELECT DISTINCT user_id
FROM user_activity
WHERE activity_type = 'view';

SELECT issuer_company, industry
FROM ipo_listings
WHERE issue_price > (
    SELECT AVG(issue_price)
    FROM ipo_listings
);

SELECT DISTINCT issuer_company, industry
FROM ipo_listings
WHERE issuer_company LIKE '%Mainline%';
